import{_ as e,o,c as r,a2 as s}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"기술 레퍼런스","description":"","frontmatter":{},"headers":[],"relativePath":"hermes/reference/index.md","filePath":"hermes/reference/index.md","lastUpdated":1781092690000}'),a={name:"hermes/reference/index.md"};function d(n,t,i,l,c,g){return o(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="기술-레퍼런스" tabindex="-1">기술 레퍼런스 <a class="header-anchor" href="#기술-레퍼런스" aria-label="Permalink to &quot;기술 레퍼런스&quot;">​</a></h1><div class="badge-box"><span class="badge-red">Verified</span><span class="badge-teal">v0.8.0 기준</span><span class="badge-gold">Authoritative</span></div><blockquote><p>이 섹션은 GitHub 저장소(<code>NousResearch/hermes-agent</code>)와 공식 문서(<code>hermes-agent.nousresearch.com/docs</code>)를 직접 파싱하여 정리한 <strong>검증된 레퍼런스</strong>입니다. 다른 섹션은 개념·패턴·분석을 다루고, 여기서는 **&quot;실제로 존재하는 것&quot;**만 다룹니다.</p></blockquote><h2 id="이-섹션이-존재하는-이유" tabindex="-1">이 섹션이 존재하는 이유 <a class="header-anchor" href="#이-섹션이-존재하는-이유" aria-label="Permalink to &quot;이 섹션이 존재하는 이유&quot;">​</a></h2><p>Hermes는 6주 동안 7번 릴리스했고, 기능 면적이 매우 넓습니다. 다른 섹션에서 개념을 배운 뒤 **&quot;정확한 명령 이름·정확한 설정 키·정확한 기본값&quot;**이 필요할 때 여기로 돌아오세요.</p><dl class="kv"><dt>출처 원칙</dt><dd>README + 공식 docs + 저장소 파일 트리에서 직접 확인된 항목만 기재</dd><dt>날짜</dt><dd>v0.8.0 (2026-04-08) 기준. 이후 변경은 <a href="/whats-new/">릴리스 타임라인</a>에서 확인</dd><dt>불일치 처리</dt><dd>공식 문서 간 수치가 다르면 <strong>가장 구체적인 카운트</strong>를 채택하고 주석</dd><dt>검증 안 된 것</dt><dd>&quot;not found&quot; 또는 &quot;문서 미공개&quot; 표기</dd></dl><h2 id="구성" tabindex="-1">구성 <a class="header-anchor" href="#구성" aria-label="Permalink to &quot;구성&quot;">​</a></h2><ul><li><a href="/hermes/reference/cli"><strong>CLI 명령 전체 레퍼런스</strong></a> — 모든 <code>hermes &lt;sub&gt;</code> 명령, 플래그, 슬래시 명령, 글로벌 옵션</li><li><a href="/hermes/reference/config"><strong>설정 및 환경 변수 레퍼런스</strong></a> — <code>~/.hermes/config.yaml</code>의 모든 키, 기본값, 환경 변수 전수</li><li><a href="/hermes/reference/internals"><strong>아키텍처 내부 동작</strong></a> — 엔트리 포인트, 레지스트리, SQLite 스키마, Tirith 스캐너, 플러그인 디스커버리</li></ul><h2 id="검증된-진짜-수치" tabindex="-1">검증된 &quot;진짜&quot; 수치 <a class="header-anchor" href="#검증된-진짜-수치" aria-label="Permalink to &quot;검증된 &quot;진짜&quot; 수치&quot;">​</a></h2><p>널리 인용되는 수치들 중 <strong>공식 문서에서 실제로 확인된</strong> 값들:</p><table tabindex="0"><thead><tr><th>항목</th><th>공식 값</th><th>출처</th></tr></thead><tbody><tr><td><strong>내장 도구</strong></td><td>47개 across 20 toolsets</td><td><code>tools/registry.py</code> / 공식 아키텍처 문서</td></tr><tr><td><strong>실행 백엔드</strong></td><td>6종 (local, Docker, SSH, Daytona, Singularity, Modal)</td><td>README</td></tr><tr><td><strong>메시징 플랫폼</strong></td><td>17개 (README는 &quot;15+&quot;, 문서 index는 &quot;15+&quot;, 실제 열거 17개)</td><td>공식 messaging 문서</td></tr><tr><td><strong>LLM 프로바이더</strong></td><td>~8 명시 + &quot;18+ services&quot; 주장</td><td>README + 아키텍처 문서</td></tr><tr><td><strong>Web 백엔드</strong></td><td>4개 (firecrawl, parallel, tavily, exa)</td><td>공식 configuration 문서</td></tr><tr><td><strong>TTS 엔진</strong></td><td>4개 (edge, elevenlabs, openai, neutts)</td><td>공식 configuration</td></tr><tr><td><strong>STT 엔진</strong></td><td>3개 (local, groq, openai)</td><td>공식 configuration</td></tr><tr><td><strong>플러그인 디스커버리 경로</strong></td><td>3곳</td><td>공식 개발자 가이드</td></tr></tbody></table><h2 id="공식-문서에서-누락된-것" tabindex="-1">공식 문서에서 누락된 것 <a class="header-anchor" href="#공식-문서에서-누락된-것" aria-label="Permalink to &quot;공식 문서에서 누락된 것&quot;">​</a></h2><p>공식 문서가 <strong>아직 커버하지 못한</strong> 영역들 — 이 보고서의 개념 페이지들이 일부 보강합니다.</p><div class="warning custom-block"><p class="custom-block-title">문서 공백</p><ul><li><strong>스킬 작성 스펙</strong> — <code>/docs/user-guide/skills</code>가 404. Skills Hub 카탈로그만 공개, 프론트매터 스키마·훅 이름 미공개</li><li><strong>메모리 내부 형식</strong> — <code>MEMORY.md</code>, <code>USER.md</code>, <code>SOUL.md</code> 파일 언급만 있고 스키마·수명 주기 문서 없음</li><li><strong>MCP 통합 가이드</strong> — CLI 서피스(<code>hermes mcp</code>)는 있으나 <code>/docs/user-guide/mcp/</code> 404</li><li><strong>도구 전체 카탈로그</strong> — &quot;47 tools across 20 toolsets&quot; 수치만 공개, 각 도구의 정확한 이름·인자·제약은 문서 부재</li><li><strong>트라젝토리 형식</strong> — README에 언급만, 필드 스펙 없음</li><li><strong>Atropos 환경 매뉴얼</strong> — tinker-atropos 서브모듈 존재, 실사용 문서 미완성</li></ul></div><p>이 공백들은 <strong>커뮤니티가 다음 3–6개월 안에 채워야 할 것들</strong>로 보입니다. 프로덕션 도입 전에 확인해 두세요.</p><h2 id="공식-문서에서-발견된-불일치" tabindex="-1">공식 문서에서 발견된 불일치 <a class="header-anchor" href="#공식-문서에서-발견된-불일치" aria-label="Permalink to &quot;공식 문서에서 발견된 불일치&quot;">​</a></h2><ul><li><strong>플랫폼 수</strong>: README는 &quot;15+&quot;, 문서 index도 &quot;15+&quot;로 표기하지만, 메시징 문서에 실제 열거된 플랫폼은 17개(Telegram, Discord, Slack, WhatsApp, Signal, SMS, Email, Home Assistant, Mattermost, Matrix, DingTalk, Feishu, WeCom, Weixin, BlueBubbles, Open WebUI, Webhooks)</li><li><strong>프로바이더 수</strong>: README는 ~7개 명시, 아키텍처 문서는 &quot;18+ services&quot;, getting-started는 &quot;15+&quot;. 구체 이름까지 확인된 것은 <strong>9개</strong> (Nous Portal, OpenRouter, Anthropic, OpenAI, z.ai/GLM, Kimi/Moonshot, MiniMax, DeepSeek, 커스텀)</li><li><strong>백엔드 수</strong>: README는 &quot;Six&quot; 일관. Daytona 포함 여부가 일부 비공식 글에서 다른 값으로 인용되나 <strong>공식은 항상 6종</strong></li></ul><hr><div class="tip custom-block"><p class="custom-block-title">다른 섹션과의 관계</p><ul><li>개념을 배우려면 → <a href="/hermes/features/learning-loop">핵심 기능</a>, <a href="/hermes/reusability/prompts">재사용성</a></li><li>통합 아키텍처를 짜려면 → <a href="/hermes/integration/">통합 패턴</a></li><li>정확한 명령·설정·내부 구조가 필요하면 → 이 섹션</li></ul></div>',19)])])}const p=e(a,[["render",d]]);export{h as __pageData,p as default};
